import { Routes } from '@angular/router';
import { LoanAccountComponent } from './loan-account.component';
import { LoanEntryStageComponent } from './loan-entry-stage/loan-entry-stage.component';

export const LoanAccountRoutes: Routes = [
  {
    path: '',
    component: LoanAccountComponent,
    children: [
      {
        path: '',
        redirectTo: 'account/list',
        pathMatch: 'full'
      },{
        path: 'account/list',
        component: LoanEntryStageComponent,
        data: { title: 'Loan', breadcrumb: 'Create Loan Account' }
      },
    ]
  }
];